import React, { useState } from "react";
import { parseProgrammeHTML } from "./utils/parserProgramme";

function App() {
  const [programme, setProgramme] = useState(null);

  const handleImport = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const text = await file.text();
    const parsed = parseProgrammeHTML(text);

    setProgramme(parsed);
  };

  return (
    <div style={{ padding: 40, color: "white", background: "black", minHeight: "100vh" }}>
      <h1>FitCoach</h1>

      <input type="file" accept=".html" onChange={handleImport} />

      {programme && (
        <div style={{ marginTop: 30 }}>
          <h2>{programme.name}</h2>

          {programme.weeks.map((week, i) => (
            <div key={i}>
              <h3>{week.name}</h3>

              {week.sessions.map((session, j) => (
                <div key={j}>
                  <h4>{session.name}</h4>

                  {session.exercises.map((ex, k) => (
                    <div key={k}>
                      {ex.name} — {ex.sets}x{ex.reps}
                    </div>
                  ))}
                </div>
              ))}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default App;
